+    // ── dot_product ──
+
+    #[test]
+    fn dot_product_identical_unit_vectors() {
+        let v = [1.0_f32, 0.0, 0.0];
+        assert!((dot_product(&v, &v) - 1.0).abs() < f32::EPSILON);
