+    // ── Search edge cases ──
+
+    #[test]
+    fn search_k_zero_returns_empty() {
+        let mut index = VectorIndex::new(VectorIndexConfig {
+            dimension: 3,
+            ..Default::default()
+        });
+        index
+            .upsert(make_entry(1, DocKind::Message, &[1.0, 0.0, 0.0]))
+            .unwrap();
+
+        let results = index.search(&[1.0, 0.0, 0.0], 0, None).unwrap();
+        assert!(results.is_empty());
